#define _CRT_SECURE_NO_WARNINGS 1#include<stdio.h>struct S{	int a;	char c;	char arr[20];	double d;};struct T{	char ch[10];	struct S s;	char* pc;};int main(){	char arr[] = "hello bits\n";	struct T t = { "hehe", {100, 'w', "hello world", 3.14}, arr};	printf("%s\n", t.ch);			//댔丹hehe	printf("%s\n", t.s.arr);		//댔丹써뭐竟냥逃코돨hello world	printf("%lf\n", t.s.d);		//댔丹3.14	printf("%s\n", t.pc);			//댔丹hello bit	return 0;}